toml_template:
[[instances]]
urls = [{{range $i, $v := split .urls ","}}{{if $i}}, {{end}}"{{trim $v}}"{{end}}]
{{- if .username}}
username = "{{.username}}"
password = "{{.password}}"
{{- end}}
{{- if .metric_name_filter}}
name_filter = "{{.metric_name_filter}}"
{{- end}}
labels = { instance="{{.urls}}" }
interval = "{{.interval}}"
